var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"뭐, 그림자라고 해도 이 정도인가? 별거 없군.","JPN":"なんだ、シャドウといってもこの程度か？　なんてことないな。","ENG":"So these were Shadows, huh? They weren’t so tough.","TWN":"什麼嘛，暗影就這點能耐嗎？沒什麼嘛？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 좀 조심해서 쓰라고 몇 번이나 말해?","JPN":"おい、もっと慎重に扱えって何度言やぁわかるんだ？","ENG":"Hey, how many times do I have to tell you to be careful when using this?","TWN":"喂，不是叫你用的時候小心一點嗎？到底要我說幾次？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장, 벌써 고정장치가 헐거워졌잖아. 이러면 역류된 에너지가 죄다 새어 나온다고.","JPN":"くそ、もう固定装置がゆるくなっていやがる。こうなると逆流したエネルギーが全部漏れ出すんだ。","ENG":"Damn it, the clamps have already become too loose. At this point, the energy flowing backwards will start pouring out.","TWN":"該死的，固定裝置都鬆動了，這樣逆流的電力會全部漏出來啦！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"무기라는 건 신뢰성이 중요한 거야. 험하게 써도 괜찮도록 만들어야지.","JPN":"武器なんてもんは信頼性が重要なんだ。乱暴に扱っても大丈夫なように作らなきゃ。","ENG":"Reliability is the most important factor for weapons. They should be built to last, no matter how roughly they’ve been used.","TWN":"武器最重要的就是可靠性，應該要做到怎麼使用都不會壞吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"난 용병이지 수리기사가 아냐. 그런 건 저쪽 핑크머리 아가씨에게 이야기해.","JPN":"俺は傭兵であって修理士じゃない。そういうことはそっちのピンク頭の嬢ちゃんに言ってくれ。","ENG":"I’m a mercenary, not a repairman. Go speak with the pink-haired girl over there.","TWN":"我只是個傭兵，不是維修師傅，這些話你自己去跟粉紅頭小姐說吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"덕분에 한숨 돌렸어요.","JPN":"おかげで一息つけました。","ENG":"We can take a breather now, thanks to you.","TWN":"多虧有你們才能稍微鬆口氣。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 어떻게 코핀 함보다 더 일찍 여기에 도착한 거죠?","JPN":"ところで、どうやってコフィン艦よりも早くここに到着できたんですか？","ENG":"But how were you able to arrive here faster than Coffin?","TWN":"不過你們怎麼比科芬艦還早到？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 마, 이쪽도 난리였어.","JPN":"それね。こっちもしっちゃかめっちゃかだったわ。","ENG":"Don’t get me started, it was a total mess for us too.","TWN":"別提啦，我們這邊也是一團亂。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"갑자기 우리가 반역자로 몰리질 않나, 쿠데타가 벌어지질 않나…….","JPN":"突然アタシたちが反逆者として追い込まれたり、クーデターが起きたり……","ENG":"First we were branded traitors, then a coup broke out...","TWN":"一下說我們是叛國賊，一下又搞什麼政變……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그쪽에서 보내 준 공간 좌표 계산 전문가가 아니었으면 애초에 도착하지도 못했을 거야.","JPN":"そちらから派遣してくれた、空間座標の計算士でなかったらそもそも到着できたかも怪しいわね。","ENG":"If it weren’t for the space coordinates calculation expert that you sent to us, we wouldn’t have been able to arrive here in the first place.","TWN":"要不是有你們派來的空間座標計算專家，我們根本不可能抵達這裡。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"공간 좌표 계산 전문가? 우리 회사에 그런 사람이 있었어요?","JPN":"空間座標の計算士？　うちの会社にそんな人いましたか？","ENG":"Space coordinates calculation expert? Was there anybody like that at our company?","TWN":"空間座標計算專家？我們公司有這種人嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"오, 얼터그레시브 실험체로군. 오랜만이다.","JPN":"お、オルタグレッシヴ実験体ではないか。久しぶりだな。","ENG":"Oh, it’s you, the Altergressive subject. Long time no see.","TWN":"喔，原來是替代進化體，好久不見。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"혹시 괜찮다면 너도 우리 다-크 세븐에 가입하지 않겠나?","JPN":"よかったらあなたもダーークセブンに入らないか？","ENG":"How would you like to join Daark Seven?","TWN":"可以的話，不如你也加入我們Dark 7的行列吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"밥도 맛있고 잠도 마음대로 잘 수 있다.","JPN":"食事もおいしく、寝るのも自由だ。","ENG":"The food is good and you get to sleep as much as you want.","TWN":"這邊伙食不錯，而且想睡就睡，完全沒問題。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"거기다 지금 가입한다면 넘버 6의 자리를 가져갈 수 있지.","JPN":"それに今入ればナンバー6の座を手に入れられる。","ENG":"Also, if you join now, you can take the position of Number 6.","TWN":"你現在加入的話，6號就歸你囉。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……그 이름을 알다니 역시 리플레이서 관계자인가?","JPN":"……その名前を知っているってことは、やはりリプレイサーの関係者？","ENG":"...Seeing that you know that name, you must be connected to the Replacers.","TWN":"……你竟然知道這個名字，你也跟克隆集團有關係嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이런 일을 할 사람은 역시 사장님뿐인데…….","JPN":"こんな事をする人は社長しかいないけれど……","ENG":"The only person who would do something like this is the Boss...","TWN":"果然，會做這種事的只有老闆……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"대체 무슨 생각이람?","JPN":"いったい何を考えているの？","ENG":"What in the world is he thinking?","TWN":"他到底在想什麼？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야? 둘이 모르는 사이야?","JPN":"うん？　知り合いじゃないの？","ENG":"Huh? You don’t know each other?","TWN":"搞什麼？你們不認識喔？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이상하네. 분명 너희 회사에서 지원 나온 인력이라고 들었는데.","JPN":"おかしいわね。確かにアンタたちの会社が応援に送った要員と聞いたんだけど。","ENG":"That’s strange. I clearly remember being told that she was sent as support from your company.","TWN":"奇怪，我明明聽說是你們公司派來的支援人力？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……그건 맞을 거예요. 별로 친하게 지낼 사이는 아니지만요.","JPN":"……それは合っていると思います。親しい仲ではないですが。","ENG":"...That’s probably correct, although she and I won’t be on the best of terms.","TWN":"……應該沒錯啦，只是我們不太熟。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 그보다 저기 보세요. 코핀 함이 오고 있네요.","JPN":"あ、それよりあれを見てください。コフィン艦が向かってきています。","ENG":"Oh, more than that though, look over there. Coffin’s arriving.","TWN":"這不重要，你們看，是科芬艦。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_COFFIN_START"},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"조금 늦었지만 이야기는 역시 높으신 분들끼리 만나서 하는 게 좋겠어요.","JPN":"遅くなりましたが、やはりお話は上の方同士で会ってされるのがいいと思います。","ENG":"Although it’s a bit late, it may be better for the higher-ups to meet and discuss the situation.","TWN":"雖然來得有點晚，不過還是等高層見面後再說吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아마 이번 작전… 제 예상이지만 오비탈 베이스를 회수하는 선에서 끝날 것 같진 않거든요.","JPN":"たぶん今回の作戦……私の予想ですが、オービタルベースを回収するだけでは終わらないと思いますから。","ENG":"My guess is that this mission won’t just end with the retrieval of the Orbital Base...","TWN":"我想…這次作戰應該不會只是回收軌道基地這麼簡單。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"예상보다 일찍 도착하셨군요.","JPN":"思ったより早く到着したんですね。","ENG":"You arrived here earlier than expected.","TWN":"比我預期的還早到呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"덕분에 저희 직원들이 도움을 받았습니다. 감사의 말을 드리고 싶군요.","JPN":"弊社の職員がお世話になりました。お礼を申し上げます。","ENG":"Thanks to you, we were able to receive assistance quickly. I wanted to express our gratitude in person.","TWN":"托你們的福，我們員工才能獲得即時的幫助，謝謝你們。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다 그쪽에서 지원해준 인력 덕분이지.","JPN":"すべてそちらが応援に送ってくれた要員のおかげだ。","ENG":"It’s all thanks to the support personnel that your boss sent to us.","TWN":"這都要謝謝你們公司派來的支援人力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"꽤 재미있는 친구를 소개해 줬더군. 아니면 악취미라고 해야 하나.","JPN":"かなり愉快な要員を紹介してくれたな。悪趣味というべきか。","ENG":"Your boss sent us quite the interesting person. Or was it one of his crude jokes?","TWN":"是一個蠻有意思的人呢，還是應該說這是個惡作劇？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"덕분에 어렸을 적의 기억이 떠올랐다네.","JPN":"おかげで幼い頃の記憶が蘇ったぞ。","ENG":"Thanks to her, I’ve been reminiscing some old memories.","TWN":"讓我想起小時候的事呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그때의 나는 저런 괴상한 장비를 가지고 놀지는 않았지만 말이야.","JPN":"そのときの私はあんな奇怪な装備で遊んだりはしなかったがな。","ENG":"Although I didn’t play with such bizarre equipment when I was that young.","TWN":"不過小時候的我，可沒帶著那麼奇怪的裝備到處跑。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"악취미라는 말에는 동감입니다. 저희 사장님이 좀 그런 면이 있지요.","JPN":"悪趣味というお言葉には同感いたします。弊社の社長は少しそういう面がありますから。","ENG":"I agree that it was a crude joke. Our Boss tends to have a quirky side to him.","TWN":"惡作劇的說法我也同意，我們老闆確實蠻喜歡惡作劇的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 그럼 개인적인 이야기는 잠시 뒤로 미뤄 두지.","JPN":"ああ。では個人的な話は後にして。","ENG":"I see. Now, let’s set aside the chit chat for a moment.","TWN":"是啊，不過這些事等以後再慢慢聊吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이 시점에 굳이 알파트릭스의 오비탈 베이스를 구하러 왔다는 건 그럴 만한 이유가 있다는 거겠지?","JPN":"現時点であえてアルペリックスのオービタルベースを救いに来たのにはそれなりの理由があるんだろう？","ENG":"Seeing that you’re here to recover Alphatrix’s Orbital Base at this point of time means that you have a good enough reason, am I correct?","TWN":"非得在這個時間點來阿爾法崔克斯的軌道基地，想必是有原因的吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 게임은 예상보다 조금 일찍 시작된 면이 있어요.","JPN":"今回のゲームは予想より少し早く始まった感があります。","ENG":"The game started earlier than we expected.","TWN":"這次遊戲比預期的還要早開始，"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 아직 준비가 충분치 못합니다.","JPN":"ですから、まだ用意が十分にできていません。","ENG":"Thus, we are still insufficiently prepared.","TWN":"因此目前準備還不夠充分。"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 최소한 이곳에서 만들고 있던 얼터니움 리액터만큼은 회수해야 했습니다.","JPN":"ですが、少なくてもここで製作していたオルタニウムリアクターだけは回収しなくてはなりませんでした。","ENG":"However, we must at the very least recover the Alternium Reactor that’s being manufactured here.","TWN":"不過至少必須將在這裡製造的黑化永恆之金電抗器回收才行。"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러지 않으면 게임 자체가 성립되지 않을 테니까요.","JPN":"でなければゲーム自体が成立しなくなりますから。","ENG":"If we fail to do so, we won’t stand a chance.","TWN":"否則，遊戲本身便無法成立。"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"얼터니움 리액터라. 그것도 구 관리국의 손이 닿은 물건인가 보군.","JPN":"オルタニウムリアクターか。それも旧管理局の手が届く品なんだろう。","ENG":"Alternium Reactor, you say? I’m guessing it’s another brainchild of the Old Administration?","TWN":"黑化永恆之金電抗器，那也是舊管理局在經手的東西吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정확히는 저희 사장님의 손길이 닿은 물건이죠.","JPN":"正確には弊社の社長の手が届く品、ですね。","ENG":"More precisely, it is the brainchild of our Boss.","TWN":"正確來說，應該是我們老闆在經手的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구 관리국에도 저런 비현실적인 물건은 없었습니다.","JPN":"旧管理局にもあのような非現実的な品はありませんでした。","ENG":"Not even the Old Administration had such a reality-defying invention like that.","TWN":"舊管理局裡也不沒有那種非現實的東西。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사장이라면 그 로봇 말인가?","JPN":"社長というとあのロボットのことか？","ENG":"By your boss, you mean the robot?","TWN":"老闆是指那個機器人嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하긴, 정말 로봇일 리는 없다고 생각했지. 재미있는 방식으로 정체를 감추고 있군.","JPN":"まあ、本当にロボットのはずがないとは思ったが。興味深いやり方で正体を隠しているな。","ENG":"Well, I did doubt from the start that he would really be a robot. He hides his identity in an entertaining way.","TWN":"果然，我就知道他不可能真的是機器人，那只是他有趣的偽裝。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"헌데 왜 이 사태를 클리포트 <color=#ffd34c>게임</color>이라고 부르는 거지?","JPN":"で、なぜこの事態をクリフォト<color=#ffd34c>ゲーム</color>と呼ぶのだ？","ENG":"By the way, why do you call this crisis the Qliphoth <color=#ffd34c>Game</color>?","TWN":"不過，為什麼要把這個情況稱為逆卡巴拉<color=#ffd34c>遊戲</color>？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"세상의 운명을 건 싸움이라면 침공이라거나 전쟁이라고 부르는 편이 더 어울리지 않나?","JPN":"この世の運命をかけた戦いならば、侵攻とか戦争といった名で呼ぶ方が合っていると思うが？","ENG":"Considering it’s a battle to decide the fate of the world, wouldn’t invasion or war be a more appropriate term?","TWN":"若是賭上世界的命運之戰，稱為侵略或戰爭不是更合適嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……말 그대로 게임이니까요.","JPN":"……言葉通りゲームですから。","ENG":"...Because it is literally a game.","TWN":"……因為這就是個遊戲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상호간 전력을 다한 전쟁이나 침공이었다면 저흰 이미 여기에 존재할 수 없었을 겁니다.","JPN":"お互いの戦力を尽くした戦争や侵攻であったなら、私たちはここに存在することもかなわなかったでしょう。","ENG":"If it were a war or invasion with both sides putting in their full effort, we would not be still around.","TWN":"若是互相比戰力的戰爭或侵略，那我們現在可能無法站在這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이미 오래전에 멸망했겠죠.","JPN":"ずっと前にすでに滅亡していたはずです。","ENG":"We would have been wiped out a long time ago.","TWN":"應該很久以前便已經滅亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 싸움에는 룰이 있습니다. 승패의 조건도 정해져 있죠.","JPN":"この戦いにはルールがあります。勝敗の条件も定められています。","ENG":"There are rules in this battle. The conditions for victory and defeat have also been established.","TWN":"這場仗是有規則的，勝敗的條件也是決定好的，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그건 클리포트의 마왕이라 할지라도 벗어날 수 없는 절대적인 제약입니다.","JPN":"それはクリフォトの魔王といえども逃れることのできない絶対的な制約です。","ENG":"These are absolute guidelines that not even the Demon Lords of Qliphoth can violate.","TWN":"就連逆卡巴拉的魔王也必須要遵守，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 그동안 우리가 버텨올 수 있었죠.","JPN":"今まで私たちが耐えてこられた理由でもあります。","ENG":"That is the reason why we have been able to make it this far.","TWN":"所以我們才能夠撐到現在。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마왕들도 지켜야만 하는 규칙이라니 의외로군.","JPN":"魔王たちが守らねばならない規則があるとは意外だな。","ENG":"Rules that even demon lords must obey? How interesting.","TWN":"沒想到竟然連魔王也必須要遵守。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그건 또 누가 정한 거지?","JPN":"それはいったい誰が定めたものなんだ？","ENG":"Who decided these rules?","TWN":"那規則又是誰定的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저도 상세한 내막에 대해선 잘은 모릅니다만.","JPN":"私も詳しい内部事情についてはわかりかねますが。","ENG":"I’m also unclear about the details.","TWN":"詳情我也不是很清楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 정체를 아는 유일한 자의 표현에 따르면 이렇습니다.","JPN":"その存在を知る唯一の者はこのように表現します。","ENG":"However, the only person who knows the identity of this being described her like this.","TWN":"不過根據唯一知情人士的說法，"},"stage":{"bg":"MAINSTREAM_807","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>관측된 최초의 신</color>.","JPN":"<color=#ffd34c>観測された最初の神</color>と。","ENG":"<color=#ffd34c>The first god to have been observed.</color>","TWN":"是<color=#ffd34c>觀測到的原始之神</color>。"},"stage":{"bg":"MAINSTREAM_807","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"최초의 신이라…….","JPN":"最初の神、か……","ENG":"The first god, you say...","TWN":"原始之神……"},"stage":{"bg":"MAINSTREAM_807","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……재미있는 표현이야.","JPN":"……興味深い表現だ。","ENG":"...That’s an interesting description.","TWN":"……真是個有趣的說法。"},"stage":{"bg":"MAINSTREAM_807","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};